using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 4, Name = "English", Abbreviation = "ENG" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" },
    ];

    private readonly List<Course> _courses =
    [
        new()
        {
            Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
            Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, data structures, and object-oriented design principles.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy."
        },
        new()
        {
            Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms",
            Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (divide and conquer, dynamic programming, greedy algorithms).",
            Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and computational complexity. He previously worked at Google Research before joining academia."
        },
        new()
        {
            Id = 3, CourseCode = "CS 310", Title = "Database Systems",
            Description = "Introduction to database design, SQL, normalization, transaction processing, and modern NoSQL approaches.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, IsFeatured = false,
            InstructorName = "Prof. Maria Lopez", InstructorBio = "Prof. Lopez brings industry experience from Oracle and Microsoft to her teaching. She focuses on practical database design and administration."
        },
        new()
        {
            Id = 4, CourseCode = "MATH 151", Title = "Calculus I",
            Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.",
            Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, IsFeatured = true,
            InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has developed innovative approaches to teaching calculus through real-world applications."
        },
        new()
        {
            Id = 5, CourseCode = "MATH 250", Title = "Linear Algebra",
            Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to data science and machine learning.",
            Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, IsFeatured = false,
            InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson researches applied mathematics with a focus on machine learning foundations. She connects abstract algebra to modern computing applications."
        },
        new()
        {
            Id = 6, CourseCode = "PHYS 101", Title = "General Physics I",
            Description = "Mechanics, thermodynamics, and waves. Lecture and laboratory components cover Newton's laws, energy conservation, and oscillatory motion.",
            Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:00 PM", DepartmentId = 3, IsFeatured = false,
            InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist who brings hands-on laboratory experience to introductory physics education."
        },
        new()
        {
            Id = 7, CourseCode = "PHYS 220", Title = "Quantum Mechanics",
            Description = "Introduction to quantum theory: wave functions, Schrödinger equation, angular momentum, hydrogen atom, and spin.",
            Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = 3, IsFeatured = true,
            InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma is a theoretical physicist whose research spans quantum information and condensed matter physics. She makes complex quantum concepts accessible to undergraduates."
        },
        new()
        {
            Id = 8, CourseCode = "ENG 110", Title = "Academic Writing",
            Description = "Develop skills in critical reading, argumentation, research methods, and clear academic prose across disciplines.",
            Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Prof. David Hart", InstructorBio = "Prof. Hart is a published author and writing instructor with expertise in rhetoric and composition studies."
        },
        new()
        {
            Id = 9, CourseCode = "ENG 245", Title = "American Literature",
            Description = "Survey of American literary traditions from the colonial period through the 21st century, examining themes of identity, democracy, and social change.",
            Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Dr. Lisa Franklin", InstructorBio = "Dr. Franklin specializes in 20th-century American fiction and has published two books on the American literary canon."
        },
        new()
        {
            Id = 10, CourseCode = "HIST 101", Title = "World History to 1500",
            Description = "Survey of major civilizations, cultural exchanges, and transformative events from antiquity through the late medieval period.",
            Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 5, IsFeatured = false,
            InstructorName = "Dr. Michael Brown", InstructorBio = "Dr. Brown is a historian of the ancient and medieval world with archaeological fieldwork experience across three continents."
        },
    ];

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

