    padding: 0.5rem 1.25rem;
    background-color: #1a237e;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
}

.btn-search:hover {
    background-color: #283593;
}

.filter-info {
    margin-bottom: 1rem;
    color: #555;
}

.filter-info a {
    color: #1a237e;
}

.no-results {
    color: #666;
    font-style: italic;
}

