@page "/enroll"

@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p class="page-description">Submit a request to enroll in a course. You will receive a confirmation from the registrar's office.</p>

@if (Submitted)
{
    <div class="success-message">
        <h2>✓ Request Submitted</h2>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@(Catalog.GetCourse(Model.CourseId)?.Title ?? "the selected course")</strong>
            has been received.</p>
        <p>The registrar's office will process your request within 2–3 business days.</p>
        <a href="/enroll">Submit another request</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
            <ValidationMessage For="() => Model.StudentName" />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" placeholder="e.g., STU-12345" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-control">
                <option value="0">— Select a course —</option>
                @foreach (var course in Catalog.GetCourses())
                {
                    <option value="@course.Id">@course.CourseCode – @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn-submit">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        Submitted = true;
    }
}

