toolArgs.file_text:
@page "/courses"

@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" class="filter-bar">
    <input type="text" name="search" value="@Search" placeholder="Search by title, code, or instructor..." class="search-input" />
    <select name="departmentId" class="department-select">
        <option value="">All Departments</option>
        @foreach (var dept in Catalog.GetDepartments())
        {
            <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
        }
    </select>
    <button type="submit" class="btn-search">Search</button>
</form>

@{
    var courses = Catalog.GetCourses(Search, DepartmentId);
}

@if (DepartmentId.HasValue)
{
    var dept = Catalog.GetDepartment(DepartmentId.Value);
    if (dept is not null)
    {
        <p class="filter-info">Showing courses in <strong>@dept.Name</strong> · <a href="/courses">Clear filter</a></p>
    }
}

@if (courses.Count == 0)
{
    <p class="no-results">No courses found matching your criteria.</p>
}
else
{
    <div class="course-list">
        @foreach (var course in courses)
        {
            <div class="course-row">
                <div class="course-info">
                    <span class="code">@course.CourseCode</span>
                    <a href="/courses/@course.Id" class="title">@course.Title</a>
                    <span class="meta">@course.Credits credits · @course.Schedule</span>
                </div>
                <div class="course-instructor">@course.InstructorName</div>
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

.filter-bar {
    display: flex;
    gap: 0.75rem;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
}

.search-input {
    flex: 1;
    min-width: 200px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

.department-select {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

.btn-search {
    padding: 0.5rem 1.25rem;
    background-color: #1a237e;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
}

.btn-search:hover {
    background-color: #283593;
}

.filter-info {
    margin-bottom: 1rem;
    color: #555;
}

.filter-info a {
    color: #1a237e;
}

.no-results {
    color: #666;
    font-style: italic;
}

.course-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.course-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 1.25rem;
    background: white;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
}

.course-info {
    display: flex;
    flex-direction: column;
    gap: 0.2rem;
}

.course-info .code {
    font-size: 0.8rem;
    font-weight: 600;
    color: #1a237e;
    text-transform: uppercase;
}

.course-info .title {
    font-size: 1.05rem;
    font-weight: 500;
    color: #222;
    text-decoration: none;
}

.course-info .title:hover {
    text-decoration: underline;
    color: #1a237e;
}

.course-info .meta {
    font-size: 0.85rem;
    color: #777;
}

.course-instructor {
    font-size: 0.9rem;
    color: #555;
    white-space: nowrap;
}

