toolArgs.file_text:
@page "/courses/{Id:int}"

@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

@{
    var course = Catalog.GetCourse(Id);
}

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The course you are looking for does not exist. <a href="/courses">Browse all courses</a></p>
}
else
{
    var department = Catalog.GetDepartment(course.DepartmentId);

    <PageTitle>@course.Title - Course Catalog</PageTitle>

    <nav class="breadcrumb">
        <a href="/courses">Courses</a> /
        @if (department is not null)
        {
            <a href="/courses?departmentId=@department.Id">@department.Name</a>
            <span> / </span>
        }
        <span>@course.CourseCode</span>
    </nav>

    <div class="course-detail">
        <header class="detail-header">
            <span class="course-code">@course.CourseCode</span>
            <h1>@course.Title</h1>
        </header>

        <div class="detail-grid">
            <section class="detail-main">
                <h2>Description</h2>
                <p>@course.Description</p>

                <h2>Instructor</h2>
                <div class="instructor-card">
                    <strong>@course.InstructorName</strong>
                    <p>@course.InstructorBio</p>
                </div>
            </section>

            <aside class="detail-sidebar">
                <div class="info-box">
                    <div class="info-item">
                        <span class="label">Credits</span>
                        <span class="value">@course.Credits</span>
                    </div>
                    <div class="info-item">
                        <span class="label">Schedule</span>
                        <span class="value">@course.Schedule</span>
                    </div>
                    <div class="info-item">
                        <span class="label">Department</span>
                        <span class="value">@(department?.Name ?? "N/A")</span>
                    </div>
                </div>
                <a href="/enroll?courseId=@course.Id" class="btn-enroll">Request Enrollment</a>
            </aside>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }
}

.breadcrumb {
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
    color: #666;
}

.breadcrumb a {
    color: #1a237e;
    text-decoration: none;
}

.breadcrumb a:hover {
    text-decoration: underline;
}

.detail-header {
    margin-bottom: 1.5rem;
}

.detail-header .course-code {
    font-size: 0.9rem;
    font-weight: 600;
    color: #1a237e;
    text-transform: uppercase;
}

.detail-header h1 {
    margin-top: 0.25rem;
    color: #222;
}

.detail-grid {
    display: grid;
    grid-template-columns: 1fr 300px;
    gap: 2rem;
}

@media (max-width: 768px) {
    .detail-grid {
        grid-template-columns: 1fr;
    }
}

.detail-main h2 {
    font-size: 1.1rem;
    color: #1a237e;
    margin-top: 1.5rem;
    margin-bottom: 0.5rem;
}

.detail-main h2:first-child {
    margin-top: 0;
}

.instructor-card {
    background: #f9f9f9;
    padding: 1rem;
    border-radius: 6px;
    border-left: 4px solid #1a237e;
}

.instructor-card strong {
    font-size: 1rem;
}

.instructor-card p {
    margin-top: 0.5rem;
    color: #555;
    font-size: 0.9rem;
}

.detail-sidebar .info-box {
    background: white;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
}

.info-item {
    display: flex;
    flex-direction: column;
    margin-bottom: 1rem;
}

.info-item:last-child {
    margin-bottom: 0;
}

.info-item .label {
    font-size: 0.8rem;
    font-weight: 600;
    text-transform: uppercase;
    color: #888;
}

.info-item .value {
    font-size: 1rem;
    color: #333;
    margin-top: 0.15rem;
}

.btn-enroll {
    display: block;
    text-align: center;
    margin-top: 1rem;
    padding: 0.75rem;
    background-color: #1a237e;
    color: white;
    text-decoration: none;
    border-radius: 6px;
    font-weight: 500;
}

.btn-enroll:hover {
    background-color: #283593;
}

